 import express from "express";
+import Database from "better-sqlite3";

 const app = express();
 const PORT = process.env.PORT || 3000;
+const db: Database.Database = new Database("data.db");

 app.use(express.json());

-// TODO: Implement endpoints per PRODUCT_SPEC.md
+db.pragma("foreign_keys = ON");
+
+db.exec(`
+  CREATE TABLE IF NOT EXISTS bookmarks (
+    id INTEGER PRIMARY KEY,
+    url TEXT NOT NULL,
+    title TEXT NOT NULL,
+    description TEXT,
+    created_at TEXT NOT NULL,
+    updated_at TEXT NOT NULL
+  )
+`);
+
+type Bookmark = {
+  id: number;
+  url: string;
+  title: string;
+  description: string | null;
+  created_at: string;
+  updated_at: string;
+};
+
+const selectBookmarkById = db.prepare<[number], Bookmark>(
+  "SELECT id, url, title, description, created_at, updated_at FROM bookmarks WHERE id = ?",
+);
+
+const isNonEmptyString = (value: unknown): value is string =>
+  typeof value === "string" && value.trim().length > 0;
+
+const parseId = (value: string): number | null => {
+  const id = Number(value);
+  return Number.isInteger(id) && id > 0 ? id : null;
+};
+
+app.get("/health", (_req, res) => {
+  res.status(200).json({ status: "ok" });
+});
+
+app.post("/bookmarks", (req, res) => {
+  const { url, title, description } = req.body;
+
+  if (!isNonEmptyString(url)) {
+    return res.status(400).json({ error: "url is required" });
+  }
+
+  if (!isNonEmptyString(title)) {
+    return res.status(400).json({ error: "title is required" });
+  }
+
+  const now = new Date().toISOString();
+  const result = db
+    .prepare(
+      `
+        INSERT INTO bookmarks (url, title, description, created_at, updated_at)
+        VALUES (?, ?, ?, ?, ?)
+      `,
+    )
+    .run(
+      url.trim(),
+      title.trim(),
+      typeof description === "string" ? description : null,
+      now,
+      now,
+    );
+
+  const bookmark = selectBookmarkById.get(Number(result.lastInsertRowid));
+  return res.status(201).json(bookmark);
+});
+
+app.get("/bookmarks", (_req, res) => {
+  const bookmarks = db
+    .prepare<[], Bookmark>(
+      "SELECT id, url, title, description, created_at, updated_at FROM bookmarks ORDER BY id ASC",
+    )
+    .all();
+
+  return res.status(200).json(bookmarks);
+});
+
+app.get("/bookmarks/:id", (req, res) => {
+  const id = parseId(req.params.id);
+
+  if (id === null) {
+    return res.status(404).json({ error: "bookmark not found" });
+  }
+
+  const bookmark = selectBookmarkById.get(id);
+
+  if (!bookmark) {
+    return res.status(404).json({ error: "bookmark not found" });
+  }
+
+  return res.status(200).json(bookmark);
+});
+
+app.put("/bookmarks/:id", (req, res) => {
+  const id = parseId(req.params.id);
+
+  if (id === null) {
+    return res.status(404).json({ error: "bookmark not found" });
+  }
+
+  const bookmark = selectBookmarkById.get(id);
+
+  if (!bookmark) {
+    return res.status(404).json({ error: "bookmark not found" });
+  }
+
+  const { url, title, description } = req.body;
+
+  if (url !== undefined && !isNonEmptyString(url)) {
+    return res.status(400).json({ error: "url must be non-empty" });
+  }
+
+  if (title !== undefined && !isNonEmptyString(title)) {
+    return res.status(400).json({ error: "title must be non-empty" });
+  }
+
+  const updated = {
+    url: url === undefined ? bookmark.url : url.trim(),
+    title: title === undefined ? bookmark.title : title.trim(),
+    description:
+      description === undefined
+        ? bookmark.description
+        : typeof description === "string"
+          ? description
+          : null,
+    updated_at: new Date().toISOString(),
+  };
+
+  db.prepare(
+    `
+      UPDATE bookmarks
+      SET url = ?, title = ?, description = ?, updated_at = ?
+      WHERE id = ?
+    `,
+  ).run(updated.url, updated.title, updated.description, updated.updated_at, id);
+
+  return res.status(200).json(selectBookmarkById.get(id));
+});
+
+app.delete("/bookmarks/:id", (req, res) => {
+  const id = parseId(req.params.id);
+
+  if (id === null) {
+    return res.status(404).json({ error: "bookmark not found" });
+  }
+
+  const result = db.prepare("DELETE FROM bookmarks WHERE id = ?").run(id);
+
+  if (result.changes === 0) {
+    return res.status(404).json({ error: "bookmark not found" });
+  }
+
+  return res.status(204).send();
+});

 app.listen(PORT, () => {
   console.log(`Server running on port ${PORT}`);
 });

 export default app;
+export { db };

